#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;

int n, m, s;

struct Edge
{
    int v, w;
};
vector<Edge> e[N];

int dis[N];
bool vis[N];

void Dijkstra()
{
    memset(dis, 0x3f, sizeof dis);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> q;
    q.push({0, s});
    dis[s] = 0;
    while(!q.empty())
    {
        auto [d, u] = q.top();
        q.pop();
        if(vis[u]) continue;
        vis[u] = 1;
        for(auto [v, w] : e[u])
        {
            if(dis[v] > dis[u] + w)
            {
                dis[v] = dis[u] + w;
                q.push({dis[v], v});
            }
        }
    }
}

int main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> n >> m >> s;
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        e[u].push_back({v, w});
    }
    Dijkstra();
    for(int i = 1; i <= n; i++)
        cout << dis[i] << ' ';
    return 0;
}
